56: // GetAllFiles uses the given descriptor source to return a list of file descriptors.
57: func GetAllFiles(source DescriptorSource) ([]*desc.FileDescriptor, error) {
58: 	var files []*desc.FileDescriptor
59: 	srcFiles, ok := source.(sourceWithFiles)
60: 
61: 	// If an error occurs, we still try to load as many files as we can, so that
62: 	// caller can decide whether to ignore error or not.
63: 	var firstError error
64: 	if ok {
65: 		files, firstError = srcFiles.GetAllFiles()
66: 	} else {
67: 		// Source does not implement GetAllFiles method, so use ListServices
68: 		// and grab files from there.
69: 		svcNames, err := source.ListServices()
70: 		if err != nil {
71: 			firstError = err
72: 		} else {
73: 			allFiles := map[string]*desc.FileDescriptor{}
74: 			for _, name := range svcNames {
75: 				d, err := source.FindSymbol(name)
76: 				if err != nil {
77: 					if firstError == nil {
78: 						firstError = err
79: 					}
80: 				} else {
81: 					addAllFilesToSet(d.GetFile(), allFiles)
82: 				}
83: 			}
84: 			files = make([]*desc.FileDescriptor, len(allFiles))
85: 			i := 0
86: 			for _, fd := range allFiles {
87: 				files[i] = fd
88: 				i++
89: 			}
90: 		}
91: 	}
92: 
93: 	sort.Sort(filesByName(files))
94: 	return files, firstError
95: }
