200: func decode(val string) (string, error) {
201: 	var firstErr error
202: 	var b []byte
203: 	// we are lenient and can accept any of the flavors of base64 encoding
204: 	for _, d := range base64Codecs {
205: 		var err error
206: 		b, err = d.DecodeString(val)
207: 		if err != nil {
208: 			if firstErr == nil {
209: 				firstErr = err
210: 			}
211: 			continue
212: 		}
213: 		return string(b), nil
214: 	}
215: 	return "", firstErr
216: }
