218: // MetadataToString returns a string representation of the given metadata, for
219: // displaying to users.
220: func MetadataToString(md metadata.MD) string {
221: 	if len(md) == 0 {
222: 		return "(empty)"
223: 	}
224: 
225: 	keys := make([]string, 0, len(md))
226: 	for k := range md {
227: 		keys = append(keys, k)
228: 	}
229: 	sort.Strings(keys)
230: 
231: 	var b bytes.Buffer
232: 	first := true
233: 	for _, k := range keys {
234: 		vs := md[k]
235: 		for _, v := range vs {
236: 			if first {
237: 				first = false
238: 			} else {
239: 				b.WriteString("\n")
240: 			}
241: 			b.WriteString(k)
242: 			b.WriteString(": ")
243: 			if strings.HasSuffix(k, "-bin") {
244: 				v = base64.StdEncoding.EncodeToString([]byte(v))
245: 			}
246: 			b.WriteString(v)
247: 		}
248: 	}
249: 	return b.String()
250: }
