275: // EnsureExtensions uses the given descriptor source to download extensions for
276: // the given message. It returns a copy of the given message, but as a dynamic
277: // message that knows about all extensions known to the given descriptor source.
278: func EnsureExtensions(source DescriptorSource, msg proto.Message) proto.Message {
279: 	// load any server extensions so we can properly describe custom options
280: 	dsc, err := desc.LoadMessageDescriptorForMessage(msg)
281: 	if err != nil {
282: 		return msg
283: 	}
284: 
285: 	var ext dynamic.ExtensionRegistry
286: 	if err = fetchAllExtensions(source, &ext, dsc, map[string]bool{}); err != nil {
287: 		return msg
288: 	}
289: 
290: 	// convert message into dynamic message that knows about applicable extensions
291: 	// (that way we can show meaningful info for custom options instead of printing as unknown)
292: 	msgFactory := dynamic.NewMessageFactoryWithExtensionRegistry(&ext)
293: 	dm, err := fullyConvertToDynamic(msgFactory, msg)
294: 	if err != nil {
295: 		return msg
296: 	}
297: 	return dm
298: }
