300: // fetchAllExtensions recursively fetches from the server extensions for the given message type as well as
301: // for all message types of nested fields. The extensions are added to the given dynamic registry of extensions
302: // so that all server-known extensions can be correctly parsed by grpcurl.
303: func fetchAllExtensions(source DescriptorSource, ext *dynamic.ExtensionRegistry, md *desc.MessageDescriptor, alreadyFetched map[string]bool) error {
304: 	msgTypeName := md.GetFullyQualifiedName()
305: 	if alreadyFetched[msgTypeName] {
306: 		return nil
307: 	}
308: 	alreadyFetched[msgTypeName] = true
309: 	if len(md.GetExtensionRanges()) > 0 {
310: 		fds, err := source.AllExtensionsForType(msgTypeName)
311: 		if err != nil {
312: 			return fmt.Errorf("failed to query for extensions of type %s: %v", msgTypeName, err)
313: 		}
314: 		for _, fd := range fds {
315: 			if err := ext.AddExtension(fd); err != nil {
316: 				return fmt.Errorf("could not register extension %s of type %s: %v", fd.GetFullyQualifiedName(), msgTypeName, err)
317: 			}
318: 		}
319: 	}
320: 	// recursively fetch extensions for the types of any message fields
321: 	for _, fd := range md.GetFields() {
322: 		if fd.GetMessageType() != nil {
323: 			err := fetchAllExtensions(source, ext, fd.GetMessageType(), alreadyFetched)
324: 			if err != nil {
325: 				return err
326: 			}
327: 		}
328: 	}
329: 	return nil
330: }
