332: // fullConvertToDynamic attempts to convert the given message to a dynamic message as well
333: // as any nested messages it may contain as field values. If the given message factory has
334: // extensions registered that were not known when the given message was parsed, this effectively
335: // allows re-parsing to identify those extensions.
336: func fullyConvertToDynamic(msgFact *dynamic.MessageFactory, msg proto.Message) (proto.Message, error) {
337: 	if _, ok := msg.(*dynamic.Message); ok {
338: 		return msg, nil // already a dynamic message
339: 	}
340: 	md, err := desc.LoadMessageDescriptorForMessage(msg)
341: 	if err != nil {
342: 		return nil, err
343: 	}
344: 	newMsg := msgFact.NewMessage(md)
345: 	dm, ok := newMsg.(*dynamic.Message)
346: 	if !ok {
347: 		// if message factory didn't produce a dynamic message, then we should leave msg as is
348: 		return msg, nil
349: 	}
350: 
351: 	if err := dm.ConvertFrom(msg); err != nil {
352: 		return nil, err
353: 	}
354: 
355: 	// recursively convert all field values, too
356: 	for _, fd := range md.GetFields() {
357: 		if fd.IsMap() {
358: 			if fd.GetMapValueType().GetMessageType() != nil {
359: 				m := dm.GetField(fd).(map[interface{}]interface{})
360: 				for k, v := range m {
361: 					// keys can't be nested messages; so we only need to recurse through map values, not keys
362: 					newVal, err := fullyConvertToDynamic(msgFact, v.(proto.Message))
363: 					if err != nil {
364: 						return nil, err
365: 					}
366: 					dm.PutMapField(fd, k, newVal)
367: 				}
368: 			}
369: 		} else if fd.IsRepeated() {
370: 			if fd.GetMessageType() != nil {
371: 				s := dm.GetField(fd).([]interface{})
372: 				for i, e := range s {
373: 					newVal, err := fullyConvertToDynamic(msgFact, e.(proto.Message))
374: 					if err != nil {
375: 						return nil, err
376: 					}
377: 					dm.SetRepeatedField(fd, i, newVal)
378: 				}
379: 			}
380: 		} else {
381: 			if fd.GetMessageType() != nil {
382: 				v := dm.GetField(fd)
383: 				newVal, err := fullyConvertToDynamic(msgFact, v.(proto.Message))
384: 				if err != nil {
385: 					return nil, err
386: 				}
387: 				dm.SetField(fd, newVal)
388: 			}
389: 		}
390: 	}
391: 	return dm, nil
392: }
