394: // MakeTemplate returns a message instance for the given descriptor that is a
395: // suitable template for creating an instance of that message in JSON. In
396: // particular, it ensures that any repeated fields (which include map fields)
397: // are not empty, so they will render with a single element (to show the types
398: // and optionally nested fields). It also ensures that nested messages are not
399: // nil by setting them to a message that is also fleshed out as a template
400: // message.
401: func MakeTemplate(md *desc.MessageDescriptor) proto.Message {
402: 	return makeTemplate(md, nil)
403: }
