405: func makeTemplate(md *desc.MessageDescriptor, path []*desc.MessageDescriptor) proto.Message {
406: 	switch md.GetFullyQualifiedName() {
407: 	case "google.protobuf.Any":
408: 		// empty type URL is not allowed by JSON representation
409: 		// so we must give it a dummy type
410: 		var any anypb.Any
411: 		_ = anypb.MarshalFrom(&any, &emptypb.Empty{}, protov2.MarshalOptions{})
412: 		return &any
413: 	case "google.protobuf.Value":
414: 		// unset kind is not allowed by JSON representation
415: 		// so we must give it something
416: 		return &structpb.Value{
417: 			Kind: &structpb.Value_StructValue{StructValue: &structpb.Struct{
418: 				Fields: map[string]*structpb.Value{
419: 					"google.protobuf.Value": {Kind: &structpb.Value_StringValue{
420: 						StringValue: "supports arbitrary JSON",
421: 					}},
422: 				},
423: 			}},
424: 		}
425: 	case "google.protobuf.ListValue":
426: 		return &structpb.ListValue{
427: 			Values: []*structpb.Value{
428: 				{
429: 					Kind: &structpb.Value_StructValue{StructValue: &structpb.Struct{
430: 						Fields: map[string]*structpb.Value{
431: 							"google.protobuf.ListValue": {Kind: &structpb.Value_StringValue{
432: 								StringValue: "is an array of arbitrary JSON values",
433: 							}},
434: 						},
435: 					}},
436: 				},
437: 			},
438: 		}
439: 	case "google.protobuf.Struct":
440: 		return &structpb.Struct{
441: 			Fields: map[string]*structpb.Value{
442: 				"google.protobuf.Struct": {Kind: &structpb.Value_StringValue{
443: 					StringValue: "supports arbitrary JSON objects",
444: 				}},
445: 			},
446: 		}
447: 	}
448: 
449: 	dm := dynamic.NewMessage(md)
450: 
451: 	// if the message is a recursive structure, we don't want to blow the stack
452: 	for _, seen := range path {
453: 		if seen == md {
454: 			// already visited this type; avoid infinite recursion
455: 			return dm
456: 		}
457: 	}
458: 	path = append(path, dm.GetMessageDescriptor())
459: 
460: 	// for repeated fields, add a single element with default value
461: 	// and for message fields, add a message with all default fields
462: 	// that also has non-nil message and non-empty repeated fields
463: 
464: 	for _, fd := range dm.GetMessageDescriptor().GetFields() {
465: 		if fd.IsRepeated() {
466: 			switch fd.GetType() {
467: 			case descriptorpb.FieldDescriptorProto_TYPE_FIXED32,
468: 				descriptorpb.FieldDescriptorProto_TYPE_UINT32:
469: 				dm.AddRepeatedField(fd, uint32(0))
470: 
471: 			case descriptorpb.FieldDescriptorProto_TYPE_SFIXED32,
472: 				descriptorpb.FieldDescriptorProto_TYPE_SINT32,
473: 				descriptorpb.FieldDescriptorProto_TYPE_INT32,
474: 				descriptorpb.FieldDescriptorProto_TYPE_ENUM:
475: 				dm.AddRepeatedField(fd, int32(0))
476: 
477: 			case descriptorpb.FieldDescriptorProto_TYPE_FIXED64,
478: 				descriptorpb.FieldDescriptorProto_TYPE_UINT64:
479: 				dm.AddRepeatedField(fd, uint64(0))
480: 
481: 			case descriptorpb.FieldDescriptorProto_TYPE_SFIXED64,
482: 				descriptorpb.FieldDescriptorProto_TYPE_SINT64,
483: 				descriptorpb.FieldDescriptorProto_TYPE_INT64:
484: 				dm.AddRepeatedField(fd, int64(0))
485: 
486: 			case descriptorpb.FieldDescriptorProto_TYPE_STRING:
487: 				dm.AddRepeatedField(fd, "")
488: 
489: 			case descriptorpb.FieldDescriptorProto_TYPE_BYTES:
490: 				dm.AddRepeatedField(fd, []byte{})
491: 
492: 			case descriptorpb.FieldDescriptorProto_TYPE_BOOL:
493: 				dm.AddRepeatedField(fd, false)
494: 
495: 			case descriptorpb.FieldDescriptorProto_TYPE_FLOAT:
496: 				dm.AddRepeatedField(fd, float32(0))
497: 
498: 			case descriptorpb.FieldDescriptorProto_TYPE_DOUBLE:
499: 				dm.AddRepeatedField(fd, float64(0))
500: 
501: 			case descriptorpb.FieldDescriptorProto_TYPE_MESSAGE,
502: 				descriptorpb.FieldDescriptorProto_TYPE_GROUP:
503: 				dm.AddRepeatedField(fd, makeTemplate(fd.GetMessageType(), path))
504: 			}
505: 		} else if fd.GetMessageType() != nil {
506: 			dm.SetField(fd, makeTemplate(fd.GetMessageType(), path))
507: 		}
508: 	}
509: 	return dm
510: }
