526: // ClientTLSConfig builds transport-layer config for a gRPC client using the
527: // given properties. If cacertFile is blank, only standard trusted certs are used to
528: // verify the server certs. If clientCertFile is blank, the client will not use a client
529: // certificate. If clientCertFile is not blank then clientKeyFile must not be blank.
530: func ClientTLSConfig(insecureSkipVerify bool, cacertFile, clientCertFile, clientKeyFile string) (*tls.Config, error) {
531: 	var tlsConf tls.Config
532: 
533: 	if clientCertFile != "" {
534: 		// Load the client certificates from disk
535: 		certificate, err := tls.LoadX509KeyPair(clientCertFile, clientKeyFile)
536: 		if err != nil {
537: 			return nil, fmt.Errorf("could not load client key pair: %v", err)
538: 		}
539: 		tlsConf.Certificates = []tls.Certificate{certificate}
540: 	}
541: 
542: 	if insecureSkipVerify {
543: 		tlsConf.InsecureSkipVerify = true
544: 	} else if cacertFile != "" {
545: 		// Create a certificate pool from the certificate authority
546: 		certPool := x509.NewCertPool()
547: 		ca, err := ioutil.ReadFile(cacertFile)
548: 		if err != nil {
549: 			return nil, fmt.Errorf("could not read ca certificate: %v", err)
550: 		}
551: 
552: 		// Append the certificates from the CA
553: 		if ok := certPool.AppendCertsFromPEM(ca); !ok {
554: 			return nil, errors.New("failed to append ca certs")
555: 		}
556: 
557: 		tlsConf.RootCAs = certPool
558: 	}
559: 
560: 	return &tlsConf, nil
561: }
