608: // BlockingDial is a helper method to dial the given address, using optional TLS credentials,
609: // and blocking until the returned connection is ready. If the given credentials are nil, the
610: // connection will be insecure (plain-text).
611: func BlockingDial(ctx context.Context, network, address string, creds credentials.TransportCredentials, opts ...grpc.DialOption) (*grpc.ClientConn, error) {
612: 	// grpc.Dial doesn't provide any information on permanent connection errors (like
613: 	// TLS handshake failures). So in order to provide good error messages, we need a
614: 	// custom dialer that can provide that info. That means we manage the TLS handshake.
615: 	result := make(chan interface{}, 1)
616: 
617: 	writeResult := func(res interface{}) {
618: 		// non-blocking write: we only need the first result
619: 		select {
620: 		case result <- res:
621: 		default:
622: 		}
623: 	}
624: 
625: 	// custom credentials and dialer will notify on error via the
626: 	// writeResult function
627: 	if creds != nil {
628: 		creds = &errSignalingCreds{
629: 			TransportCredentials: creds,
630: 			writeResult:          writeResult,
631: 		}
632: 	}
633: 	dialer := func(ctx context.Context, address string) (net.Conn, error) {
634: 		// NB: We *could* handle the TLS handshake ourselves, in the custom
635: 		// dialer (instead of customizing both the dialer and the credentials).
636: 		// But that requires using insecure.NewCredentials() dial transport
637: 		// option (so that the gRPC library doesn't *also* try to do a
638: 		// handshake). And that would mean that the library would send the
639: 		// wrong ":scheme" metaheader to servers: it would send "http" instead
640: 		// of "https" because it is unaware that TLS is actually in use.
641: 		conn, err := (&net.Dialer{}).DialContext(ctx, network, address)
642: 		if err != nil {
643: 			writeResult(err)
644: 		}
645: 		return conn, err
646: 	}
647: 
648: 	// Even with grpc.FailOnNonTempDialError, this call will usually timeout in
649: 	// the face of TLS handshake errors. So we can't rely on grpc.WithBlock() to
650: 	// know when we're done. So we run it in a goroutine and then use result
651: 	// channel to either get the connection or fail-fast.
652: 	go func() {
653: 		// We put grpc.FailOnNonTempDialError *before* the explicitly provided
654: 		// options so that it could be overridden.
655: 		opts = append([]grpc.DialOption{grpc.FailOnNonTempDialError(true)}, opts...)
656: 		// But we don't want caller to be able to override these two, so we put
657: 		// them *after* the explicitly provided options.
658: 		opts = append(opts, grpc.WithBlock(), grpc.WithContextDialer(dialer))
659: 
660: 		if creds == nil {
661: 			opts = append(opts, grpc.WithTransportCredentials(insecure.NewCredentials()))
662: 		} else {
663: 			opts = append(opts, grpc.WithTransportCredentials(creds))
664: 		}
665: 		conn, err := grpc.DialContext(ctx, address, opts...)
666: 		var res interface{}
667: 		if err != nil {
668: 			res = err
669: 		} else {
670: 			res = conn
671: 		}
672: 		writeResult(res)
673: 	}()
674: 
675: 	select {
676: 	case res := <-result:
677: 		if conn, ok := res.(*grpc.ClientConn); ok {
678: 			return conn, nil
679: 		}
680: 		return nil, res.(error)
681: 	case <-ctx.Done():
682: 		return nil, ctx.Err()
683: 	}
684: }
