686: // errSignalingCreds is a wrapper around a TransportCredentials value, but
687: // it will use the writeResult function to notify on error.
688: type errSignalingCreds struct {
689: 	credentials.TransportCredentials
690: 	writeResult func(res interface{})
691: }
692: 
693: func (c *errSignalingCreds) ClientHandshake(ctx context.Context, addr string, rawConn net.Conn) (net.Conn, credentials.AuthInfo, error) {
694: 	conn, auth, err := c.TransportCredentials.ClientHandshake(ctx, addr, rawConn)
695: 	if err != nil {
696: 		c.writeResult(err)
697: 	}
698: 	return conn, auth, err
